const PopoverCombobox = () => {
  return (
    <PopoverContainer baseId="popover-example">
      <PopoverButton variant="primary">Open</PopoverButton>
      <Popover aria-label="Popover">
        <Combobox items={items} labelText="Select an item" usePortal={false} />
      </Popover>
    </PopoverContainer>  
  );
};

render(
  <PopoverCombobox />
)
